// ==================== 模拟数据辅助函数 ====================

/**
 * 如果真实数据是空数组，返回模拟数据
 */
export function fallbackArray(realData, mockData) {
  if (Array.isArray(realData) && realData.length > 0) return realData;
  return mockData;
}

/**
 * 如果真实数据是 null/空对象，返回模拟数据
 */
export function fallbackObject(realData, mockData) {
  if (realData && typeof realData === 'object' && Object.keys(realData).length > 0) return realData;
  return mockData;
}
